if (api.options.autoExpand) {
  (function() {
    function expandOnce(root) {
      if (!root) return;
      var btns = root.querySelectorAll('button');
      for (var i = 0; i < btns.length; i++) {
        var txt = btns[i].textContent.trim();
        if (txt.indexOf('Show') === 0 && txt.indexOf('more') !== -1) {
          btns[i].click();
          api.log('Clicked: ' + txt);
          return;
        }
      }
    }
    var lastExpandTime = 0;
    var debounceTimer = null;
    var observer = new MutationObserver(function() {
      if (debounceTimer) return;
      var now = Date.now();
      if (now - lastExpandTime < 2000) return;
      debounceTimer = setTimeout(function() {
        debounceTimer = null;
        var dialog = document.querySelector('.prc-Dialog-Dialog-G8cDF, div[role="dialog"]');
        if (dialog) {
          lastExpandTime = Date.now();
          expandOnce(dialog);
        }
      }, 250);
    });
    observer.observe(document.body, { childList: true, subtree: true });
    api.log('Hamburger auto-expand initialized');
  })();
}

if (api.options.autoDevBranch) {
  (function() {
    var path = location.pathname.split('/').filter(Boolean);
    if (path.length !== 2) return;
    if (location.search || location.hash) return;
    var repoKey = path[0] + '/' + path[1];
    var CACHE_KEY = '__billiax_dev_branches';
    var cache = {};
    try { cache = JSON.parse(localStorage.getItem(CACHE_KEY) || '{}'); } catch {}
    function switchToDev() {
      if (!location.pathname.includes('/tree/dev')) {
        api.log('Switching to dev branch for ' + repoKey);
        location.replace('/' + repoKey + '/tree/dev');
      }
    }
    if (cache[repoKey] === true) { switchToDev(); return; }
    if (cache[repoKey] === false) return;
    fetch(location.href, { credentials: 'same-origin' })
      .then(function(r) { return r.text(); })
      .then(function(html) {
        var hasDev = html.indexOf('/tree/dev') !== -1 || html.indexOf('"dev"') !== -1;
        cache[repoKey] = hasDev;
        try { localStorage.setItem(CACHE_KEY, JSON.stringify(cache)); } catch {}
        if (hasDev) switchToDev();
      })
      .catch(function() {});
  })();
}
